param([Parameter(Mandatory=$true)][ValidateSet('validate_operation_registry','compile_prompt','finalize_asset_review','finalize_delivery_review','validate_work_package')][string]$Mode,[string]$ProjectRoot='',[string]$RegistryPath='',[string]$BriefPath='',[string]$RoutePath='',[string]$InputPath='',[string]$OutputPath='',[string]$PostprocessOutputPath='',[string]$Timestamp='',[string]$CurrentAssetSha256='',[string]$CurrentHtmlSha256='')
Set-StrictMode -Version 2.0;$ErrorActionPreference='Stop';if([string]::IsNullOrWhiteSpace($ProjectRoot)){$ProjectRoot=Split-Path -Parent $PSScriptRoot};if([string]::IsNullOrWhiteSpace($RegistryPath)){$RegistryPath=Join-Path $ProjectRoot 'routes/r7-visual-operation-registry.yaml'};. (Join-Path $PSScriptRoot 'R7VisualSemanticRuntime.ps1')
try{$result=switch($Mode){'validate_operation_registry'{Get-R7VisualOperationRegistry $ProjectRoot $RegistryPath}'compile_prompt'{Invoke-R7DeterministicPromptCompile $ProjectRoot $RegistryPath $BriefPath $RoutePath $Timestamp $OutputPath $PostprocessOutputPath}'finalize_asset_review'{Complete-R7VisualAssetReview $InputPath $OutputPath $CurrentAssetSha256}'finalize_delivery_review'{Complete-R7DeliveryVisualReview $InputPath $OutputPath $CurrentHtmlSha256}'validate_work_package'{$registry=Get-R7VisualOperationRegistry $ProjectRoot $RegistryPath;$package=Read-R7VisualJson $InputPath;$errors=@(Test-R7VisualSemanticWorkPackage $package $registry.Digest);if($errors.Count){throw 'visual_semantic_work_package_invalid:'+([string]::Join('|',$errors))};$package}};[pscustomobject]@{result_code='pass';mode=$Mode;output_path=$OutputPath}|ConvertTo-Json -Compress;exit 0}catch{[Console]::Error.WriteLine($_.Exception.Message);exit 1}
